toolArgs.file_text:
.message-item {
    padding: 8px 16px;
    position: relative;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-item:hover {
    background: #f5f5f5;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 14px;
    color: #1a1a1a;
}

.timestamp {
    font-size: 12px;
    color: #888;
}

.message-content {
    font-size: 14px;
    line-height: 1.5;
    color: #333;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    background: #eef1f5;
    border: 1px solid #d8dce3;
    border-radius: 12px;
    font-size: 13px;
    cursor: pointer;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #dce3ee;
}

.thread-link {
    background: none;
    border: none;
    color: #4a76a8;
    font-size: 13px;
    font-weight: 500;
    cursor: pointer;
    padding: 4px 0;
    margin-top: 2px;
}

.thread-link:hover {
    text-decoration: underline;
}

.action-bar {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    overflow: hidden;
}

.action-btn {
    background: none;
    border: none;
    padding: 4px 10px;
    font-size: 13px;
    cursor: pointer;
    white-space: nowrap;
    color: #555;
    transition: background 0.1s;
}

.action-btn:hover {
    background: #f0f0f0;
}

.emoji-picker {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    padding: 6px 8px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
    width: fit-content;
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 20px;
    cursor: pointer;
    padding: 4px;
    border-radius: 4px;
    transition: background 0.1s;
    line-height: 1;
}

.emoji-btn:hover {
    background: #f0f0f0;
}

