{"file_text": "@namespace sv_1c981689e12144ce9a0365708b4eab5e.Components.Chat
@using sv_1c981689e12144ce9a0365708b4eab5e.Services
@inject IJSRuntime JS

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="area-header">
            <h2># @Channel.Name</h2>
            <span class="area-description">@Channel.Description</span>
        </div>

        <div class="message-list" @ref="_messageListRef" @onscroll="HandleScroll">
            @if (HasMoreMessages)
            {
                <div class="load-more">
                    @if (IsLoadingOlder)
                    {
                        <span>Loading older messages…</span>
                    }
                </div>
            }

            @foreach (var msg in Messages)
            {
                <MessageItem Message="msg"
                             ReplyCount="GetReplyCount(msg.Id)"
                             OnOpenThread="OnOpenThread"
                             OnReact="OnReact" />
            }
        </div>

        <MessageInput Placeholder="@($"Message #{Channel.Name}")" OnSubmit="OnSendMessage" />
    }
    else
    {
        <div class="no-channel-selected">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public bool IsLoadingOlder { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadOlder { get; set; }

    private ElementReference _messageListRef;
    private bool _shouldScrollToBottom = true;
    private int _previousMessageCount;

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.GetValueOrDefault(messageId);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (_shouldScrollToBottom)
        {
            _shouldScrollToBottom = false;
            await ScrollToBottom();
        }
    }

    protected override void OnParametersSet()
    {
        if (Messages.Count != _previousMessageCount && Messages.Count > 0)
        {
            // Scroll to bottom only when new messages are added (not when loading older)
            if (Messages.Count > _previousMessageCount &&
                _previousMessageCount > 0 &&
                Messages[^1].Id != (Messages.Count > 1 ? Messages[^2].Id : 0))
            {
                _shouldScrollToBottom = true;
            }
            else if (_previousMessageCount == 0)
            {
                _shouldScrollToBottom = true;
            }

            _previousMessageCount = Messages.Count;
        }
    }

    private async Task HandleScroll()
    {
        if (IsLoadingOlder || !HasMoreMessages) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('[b-message-area-scroll]')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            await OnLoadOlder.InvokeAsync();
        }
    }

    private async Task ScrollToBottom()
    {
        try
        {
            await JS.InvokeVoidAsync("eval",
                "setTimeout(() => { const el = document.querySelector('.message-list'); if (el) el.scrollTop = el.scrollHeight; }, 50)");
        }
        catch (JSException)
        {
            // Element not yet available
        }
    }
}
