arguments.file_text:
@page "/chat"
@layout ChatLayout
@using sv_1c981689e12144ce9a0365708b4eab5e.Components.Chat
@using sv_1c981689e12144ce9a0365708b4eab5e.Components.Layout
@using sv_1c981689e12144ce9a0365708b4eab5e.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <div class="sidebar-panel">
        <ChannelSidebar Channels="_channels"
                        SelectedChannelId="_selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-panel @(_threadOpen ? "with-thread" : "")">
        <MessageArea Channel="_selectedChannel"
                     Messages="_topLevelMessages"
                     ThreadReplyCounts="_replyCounts"
                     HasMoreMessages="_hasMoreMessages"
                     IsLoadingOlder="_isLoadingOlder"
                     OnOpenThread="OpenThread"
                     OnReact="HandleReaction"
                     OnSendMessage="SendMessage"
                     OnLoadOlder="LoadOlderMessages" />
    </div>

    @if (_threadOpen && _threadRootMessage is not null)
    {
        <div class="thread-panel-container">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         IsLoading="_isThreadLoading"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> _channels = [];
    private int _selectedChannelId;
    private Channel? _selectedChannel;

    private List<Message> _allMessages = [];
