+        }
+
+        _allMessages.InsertRange(0, messages);
+        _skip += messages.Count;
+        RebuildMessageViews();
+    }
+
+    private async Task LoadOlderMessages()
+    {
+        if (_isLoadingOlder || !_hasMoreMessages) return;
+
+        _isLoadingOlder = true;
+        StateHasChanged();
+
+        await LoadMessages();
+
+        _isLoadingOlder = false;
+    }
